    const amount = information.amount;

    // Creating each tag
    const payloadFormatIndicator = new PayloadFormatIndicator(emv.PAYLOAD_FORMAT_INDICATOR, emv.DEFAULT_PAYLOAD_FORMAT_INDICATOR);

    // Static QR is when QR Code has no amount tag
